import json
from datetime import datetime
from flask import Flask, request, make_response

app = Flask(__name__)
cache = {}

@app.route('/')
def index():
    response = make_response(json.dumps({'message': 'Hello World!'}), 200)
    response.headers['Content-Type'] = 'application/json'
    return response

@app.route('/cache', methods=['GET'])
def cache_get():
    key = request.args.get('key')
    if key in cache:
        response = make_response(json.dumps({'message': f'Cache hit for {key}'}), 200)
        response.headers['Content-Type'] = 'application/json'
        return response
    else:
        response = make_response(json.dumps({'message': f'Cache miss for {key}'}), 404)
        response.headers['Content-Type'] = 'application/json'
        return response

@app.route('/cache', methods=['POST'])
def cache_post():
    key = request.args.get('key')
    data = json.loads(request.data)
    cache[key] = (datetime.now(), data)
    response = make_response(json.dumps({'message': f'Cache updated for {key}'}), 201)
    response.headers['Content-Type'] = 'application/json'
    return response

@app.route('/cache', methods=['DELETE'])
def cache_delete():
    key = request.args.get('key')
    if key in cache:
        del cache[key]
        response = make_response(json.dumps({'message': f'Cache deleted for {key}'}), 200)
        response.headers['Content-Type'] = 'application/json'
        return response
    else:
        response = make_response(json.dumps({'message': f'Cache miss for {key}'}), 404)
        response.headers['Content-Type'] = 'application/json'
        return response